{
  "title": "उचित उद्धरण",
  "group": "उद्धरण 1",
  "options": [
    {
      "text": "दोनों समान काम करते हैं"
    },
    {
      "text": "डबल कोट्स आवश्यक हैं"
    },
    {
      "text": "सिंगल कोट्स आवश्यक हैं"
    },
    {
      "text": "सिंटैक्स त्रुटि: अमान्य उपयोगकर्ता लिटरल"
    },
    {
      "text": "सभी नाम लोअरकेस होना चाहिए"
    }
  ],
  "questionProse": [
    "केस-सेंसिटिव कॉलम नामों के लिए कौन सा सही है?"
  ],
  "explanationProse": [
    "PostgreSQL में:\n    - डबल कोट्स (`\"`) पहचानकर्ताओं (टेबल नाम, कॉलम नाम) के लिए होते हैं\n    - सिंगल कोट्स (`'`) स्ट्रिंग लिटरल्स के लिए होते हैं\n\n    सर्वोत्तम अभ्यास:\n    - नामों में मिश्रित केस या स्पेस से बचें\n    - पहचानकर्ताओं के लिए snake_case उपयोग करें\n    - केवल तभी कोटेड पहचानकर्ता उपयोग करें जब बिल्कुल आवश्यक हो"
  ]
}
